*/

#ifndefZEPHYR_INCLUDE_NET_PPP_H_
#defineZEPHYR_INCLUDE_NET_PPP_H_

#include<zephyr/net/net_if.h>
#include<zephyr/net/net_pkt.h>
#include<zephyr/net/net_stats.h>
#include<zephyr/net/net_mgmt.h>

#ifdef__cplusplus
extern"C"{
#endif

#definePPP_MRUCONFIG_NET_PPP_MTU_MRU

#definePPP_MTUPPP_MRU

#definePPP_MAX_TERMINATE_REASON_LEN32

#definePPP_INTERFACE_IDENTIFIER_LEN8

structppp_api{
structnet_if_apiiface_api;

int(*start)(conststructdevice*dev);

int(*stop)(conststructdevice*dev);

int(*send)(conststructdevice*dev,structnet_pkt*pkt);

#ifdefined(CONFIG_NET_STATISTICS_PPP)
structnet_stats_ppp*(*get_stats)(conststructdevice*dev);
#endif
};

/*MakesurethatthenetworkinterfaceAPIisproperlysetupinside
*PPPAPIstruct(itisthefirstone).
*/
BUILD_ASSERT(offsetof(structppp_api,iface_api)==0);

enumppp_protocol_type{
PPP_IP=0x0021,
PPP_IPV6=0x0057,
PPP_IPCP=0x8021,
PPP_ECP=0x8053,
PPP_IPV6CP=0x8057,
PPP_CCP=0x80FD,
PPP_LCP=0xc021,
PPP_PAP=0xc023,
PPP_CHAP=0xc223,
PPP_EAP=0xc227,
};

enumppp_phase{
PPP_DEAD,
PPP_ESTABLISH,
PPP_AUTH,
PPP_NETWORK,
PPP_RUNNING,
PPP_TERMINATE,
};

enumppp_state{
PPP_INITIAL,
PPP_STARTING,
PPP_CLOSED,
PPP_STOPPED,
PPP_CLOSING,
PPP_STOPPING,
PPP_REQUEST_SENT,
PPP_ACK_RECEIVED,
PPP_ACK_SENT,
PPP_OPENED
};

enumppp_packet_type{
PPP_CONFIGURE_REQ=1,
PPP_CONFIGURE_ACK=2,
PPP_CONFIGURE_NACK=3,
PPP_CONFIGURE_REJ=4,
PPP_TERMINATE_REQ=5,
PPP_TERMINATE_ACK=6,
PPP_CODE_REJ=7,
PPP_PROTOCOL_REJ=8,
PPP_ECHO_REQ=9,
PPP_ECHO_REPLY=10,
PPP_DISCARD_REQ=11
};

enumlcp_option_type{
LCP_OPTION_RESERVED=0,

LCP_OPTION_MRU=1,

LCP_OPTION_ASYNC_CTRL_CHAR_MAP=2,

LCP_OPTION_AUTH_PROTO=3,

LCP_OPTION_QUALITY_PROTO=4,

LCP_OPTION_MAGIC_NUMBER=5,

LCP_OPTION_PROTO_COMPRESS=7,

LCP_OPTION_ADDR_CTRL_COMPRESS=8
}__packed;

enumipcp_option_type{
IPCP_OPTION_RESERVED=0,

IPCP_OPTION_IP_ADDRESSES=1,

IPCP_OPTION_IP_COMP_PROTO=2,

IPCP_OPTION_IP_ADDRESS=3,

/*RFC1877*/

IPCP_OPTION_DNS1=129,

IPCP_OPTION_NBNS1=130,

IPCP_OPTION_DNS2=131,

IPCP_OPTION_NBNS2=132,
}__packed;

enumipv6cp_option_type{
IPV6CP_OPTION_RESERVED=0,

IPV6CP_OPTION_INTERFACE_IDENTIFIER=1,
}__packed;

typedefvoid(*net_ppp_lcp_echo_reply_cb_t)(void*user_data,
size_tuser_data_len);

structppp_my_option_data;
structppp_my_option_info;

structppp_fsm{
structk_work_delayabletimer;

struct{
int(*config_info_ack)(structppp_fsm*fsm,
structnet_pkt*pkt,
uint16_tlength);

structnet_pkt*(*config_info_add)(structppp_fsm*fsm);

int(*config_info_len)(structppp_fsm*fsm);

int(*config_info_nack)(structppp_fsm*fsm,
structnet_pkt*pkt,
uint16_tlength,
boolrejected);

int(*config_info_req)(structppp_fsm*fsm,
structnet_pkt*pkt,
uint16_tlength,
structnet_pkt*ret_pkt);

int(*config_info_rej)(structppp_fsm*fsm,
structnet_pkt*pkt,
uint16_tlength);

void(*config_info_reset)(structppp_fsm*fsm);

void(*up)(structppp_fsm*fsm);

void(*down)(structppp_fsm*fsm);

void(*starting)(structppp_fsm*fsm);

void(*finished)(structppp_fsm*fsm);

void(*proto_reject)(structppp_fsm*fsm);

void(*retransmit)(structppp_fsm*fsm);

enumnet_verdict(*proto_extension)(structppp_fsm*fsm,
enumppp_packet_typecode,
uint8_tid,
structnet_pkt*pkt);
}cb;

struct{
conststructppp_my_option_info*info;

structppp_my_option_data*data;

size_tcount;
}my_options;

uint32_tflags;

;uint32_tretransmits;

uint32_tnack_loops;

uint32_trecv_nack_loops;

charterminate_reason[PPP_MAX_TERMINATE_REASON_LEN];

uint16_tprotocol;

enumppp_statestate;

constchar*name;

uint8_tid;

uint8_treq_id;

uint8_tack_received:1;
};

#definePPP_MY_OPTION_ACKEDBIT(0)
#definePPP_MY_OPTION_REJECTEDBIT(1)

structppp_my_option_data{
uint32_tflags;
};

#ifdefined(CONFIG_NET_L2_PPP_OPTION_DNS_USE)
#defineIPCP_NUM_MY_OPTIONS3
#else
#defineIPCP_NUM_MY_OPTIONS1
#endif
#defineIPV6CP_NUM_MY_OPTIONS1

enumppp_flags{
PPP_CARRIER_UP,
};

structlcp_options{
uint32_tmagic;

uint32_tasync_map;

uint16_tmru;

uint16_tauth_proto;
};

#ifdefined(CONFIG_NET_L2_PPP_OPTION_MRU)
#defineLCP_NUM_MY_OPTIONS2
#else
#defineLCP_NUM_MY_OPTIONS1
#endif

structipcp_options{
structnet_in_addraddress;

structnet_in_addrdns1_address;

structnet_in_addrdns2_address;
};

structipv6cp_options{
uint8_tiid[PPP_INTERFACE_IDENTIFIER_LEN];
};

structppp_context{
atomic_tflags;

structk_work_delayablestartup;

struct{
structppp_fsmfsm;

structlcp_optionsmy_options;

structlcp_optionspeer_options;

uint32_tmagic;

structppp_my_option_datamy_options_data[LCP_NUM_MY_OPTIONS];
}lcp;

#ifdefined(CONFIG_NET_IPV4)
struct{
structppp_fsmfsm;

structipcp_optionsmy_options;

structipcp_optionspeer_options;

structppp_my_option_datamy_options_data[IPCP_NUM_MY_OPTIONS];
}ipcp;
#endif

#ifdefined(CONFIG_NET_IPV6)
struct{
structppp_fsmfsm;

structipv6cp_optionsmy_options;

structipv6cp_optionspeer_options;

structppp_my_option_datamy_options_data[IPV6CP_NUM_MY_OPTIONS];
}ipv6cp;
#endif

#ifdefined(CONFIG_NET_L2_PPP_PAP)
struct{
structppp_fsmfsm;
}pap;
#endif

#ifdefined(CONFIG_NET_SHELL)
struct{
struct{
net_ppp_lcp_echo_reply_cb_tcb;

void*user_data;

size_tuser_data_len;
}echo_reply;

structk_semwait_echo_reply;

uint32_techo_req_data;

uint32_techo_reply_data;
}shell;
#endif

structnet_if*iface;

structnet_mgmt_event_callbackmgmt_evt_cb;

enumppp_phasephase;

structk_semwait_ppp_link_terminated;

structk_semwait_ppp_link_down;

enumnet_l2_flagsppp_l2_flags;

intnetwork_protos_open;

intnetwork_protos_up;

uint16_tis_ready_to_serve:1;

uint16_tis_enabled:1;

uint16_tis_enable_done:1;

uint16_tis_ipcp_up:1;

uint16_tis_ipcp_open:1;

uint16_tis_ipv6cp_up:1;

uint16_tis_ipv6cp_open:1;

uint16_tis_pap_up:1;

uint16_tis_pap_open:1;
};

voidnet_ppp_init(structnet_if*iface);

/*ManagementAPIforPPP*/

#definePPP_L2_CTX_TYPEstructppp_context

#defineNET_PPP_LAYERNET_MGMT_LAYER_L2
#defineNET_PPP_CODENET_MGMT_LAYER_CODE_PPP
#defineNET_PPP_BASE(NET_MGMT_IFACE_BIT|\
NET_MGMT_LAYER(NET_PPP_LAYER)|\
NET_MGMT_LAYER_CODE(NET_PPP_CODE))
#defineNET_PPP_EVENT(NET_PPP_BASE|NET_MGMT_EVENT_BIT)

enum{
NET_EVENT_PPP_CMD_CARRIER_ON_VAL,
NET_EVENT_PPP_CMD_CARRIER_OFF_VAL,
NET_EVENT_PPP_CMD_PHASE_RUNNING_VAL,
NET_EVENT_PPP_CMD_PHASE_DEAD_VAL,

NET_EVENT_PPP_CMD_MAX
};

BUILD_ASSERT(NET_EVENT_PPP_CMD_MAX<=NET_MGMT_MAX_COMMANDS,
"Numberofeventsinnet_event_ppp_cmdexceedsthelimit");

enumnet_event_ppp_cmd{
NET_MGMT_CMD(NET_EVENT_PPP_CMD_CARRIER_ON),
NET_MGMT_CMD(NET_EVENT_PPP_CMD_CARRIER_OFF),
NET_MGMT_CMD(NET_EVENT_PPP_CMD_PHASE_RUNNING),
NET_MGMT_CMD(NET_EVENT_PPP_CMD_PHASE_DEAD),
};

structnet_if;

#defineNET_PPP_DEFAULT_ASYNC_MAP(0xffffffffU)

uint32_tppp_peer_async_control_character_map(structnet_if*iface);

#defineNET_EVENT_PPP_CARRIER_ON\
(NET_PPP_EVENT|NET_EVENT_PPP_CMD_CARRIER_ON)

#defineNET_EVENT_PPP_CARRIER_OFF\
(NET_PPP_EVENT|NET_EVENT_PPP_CMD_CARRIER_OFF)

#defineNET_EVENT_PPP_PHASE_RUNNING\
(NET_PPP_EVENT|NET_EVENT_PPP_CMD_PHASE_RUNNING)

#defineNET_EVENT_PPP_PHASE_DEAD\
(NET_PPP_EVENT|NET_EVENT_PPP_CMD_PHASE_DEAD)

#ifdefined(CONFIG_NET_L2_PPP_MGMT)
voidppp_mgmt_raise_carrier_on_event(structnet_if*iface);
#else
staticinlinevoidppp_mgmt_raise_carrier_on_event(structnet_if*iface)
{
ARG_UNUSED(iface);
}
#endif

#ifdefined(CONFIG_NET_L2_PPP_MGMT)
voidppp_mgmt_raise_carrier_off_event(structnet_if*iface);
#else
staticinlinevoidppp_mgmt_raise_carrier_off_event(structnet_if*iface)
{
ARG_UNUSED(iface);
}
#endif

#ifdefined(CONFIG_NET_L2_PPP_MGMT)
voidppp_mgmt_raise_phase_running_event(structnet_if*iface);
#else
staticinlinevoidppp_mgmt_raise_phase_running_event(structnet_if*iface)
{
ARG_UNUSED(iface);
}
#endif

#ifdefined(CONFIG_NET_L2_PPP_MGMT)
voidppp_mgmt_raise_phase_dead_event(structnet_if*iface);
#else
staticinlinevoidppp_mgmt_raise_phase_dead_event(structnet_if*iface)
{
ARG_UNUSED(iface);
}
#endif

#ifdefined(CONFIG_NET_L2_PPP)
intnet_ppp_ping(intidx,int32_ttimeout);
#else
staticinlineintnet_ppp_ping(intidx,int32_ttimeout)
{
ARG_UNUSED(idx);
ARG_UNUSED(timeout);

return-ENOTSUP;
}
#endif

#ifdefined(CONFIG_NET_L2_PPP)&&defined(CONFIG_NET_SHELL)
structppp_context*net_ppp_context_get(intidx);
#else
staticinlinestructppp_context*net_ppp_context_get(intidx)
{
ARG_UNUSED(idx);

returnNULL;
}
#endif

#ifdef__cplusplus
}
#endif

#endif/*ZEPHYR_INCLUDE_NET_PPP_H_*/
